+
+  // seed position *near* expected solution
+  seed = expected + 0.01 * VectorXd::Random(expected.size());
+//  std::cout << "Testing seed vector: " << seed.transpose() << std::endl;
+  ik.calcInvKin(pose, seed, joints);
