+
+TEST_F(calcJacobian, knownPoses)
+{
+    VectorXd joints = VectorXd::Zero(6);
+    MatrixXd expected, result;
+
+    // all joints 0
+    EXPECT_TRUE(kin.calcJacobian(joints, result));
+    expected.resize(6,6);
+    expected << -0.12446, 0.4318,  0.4318, 0, 0, 0,
+                 0.41148, 0,       0,      0, 0, 0,
+                 0,      -0.41148, 0.0203, 0, 0, 0,
